import{_ as t,o as a,c as i,a2 as l}from"./chunks/framework.BflysNKA.js";const u=JSON.parse('{"title":"中转接口是什么","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-relay.md","filePath":"guide/what-is-relay.md","lastUpdated":1778577020000}'),r={name:"guide/what-is-relay.md"};function s(n,e,d,o,p,h){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="中转接口是什么" tabindex="-1">中转接口是什么 <a class="header-anchor" href="#中转接口是什么" aria-label="Permalink to &quot;中转接口是什么&quot;">​</a></h1><p>“中转接口”“Relay”“网关”这些词，指的都是同一类东西：<br> 让不同客户端不要各自去对接一堆模型平台，而是统一先接到一个入口，再由这个入口去做转发、鉴权、计费、日志和模型管理。</p><p>第一次接触这一层时，可以先把它理解成：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>你的客户端 -&gt; 小蓝中转站 网关 -&gt; 实际模型服务</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这不是多绕一层“显得复杂”，而是把原本散在各个平台里的配置，集中到一个地方来管。</p><h2 id="它解决的是什么问题" tabindex="-1">它解决的是什么问题 <a class="header-anchor" href="#它解决的是什么问题" aria-label="Permalink to &quot;它解决的是什么问题&quot;">​</a></h2><p>如果没有网关，常见情况会变成：</p><ul><li>Claude Code 配一套地址和 Key</li><li>Codex 再配一套</li><li>Cherry Studio 再配一套</li><li>换模型、换账号、查日志、看扣费时，还要分别回不同地方找</li></ul><p>接到 小蓝中转站 后，很多事情就能收拢到一个入口：</p><ul><li><strong>Key 集中管理</strong>：不同工具都用你在控制台创建的 Key</li><li><strong>模型统一查看</strong>：模型名以模型广场为准</li><li><strong>日志统一排查</strong>：请求成功没成功、扣费多少、报什么错，都能回控制台看</li><li><strong>权限统一控制</strong>：分组、模型权限、额度可以按设备或工具拆开</li></ul><p>对新手来说，这层最直接的价值不是“高级”，而是出了问题以后更容易知道该去哪里查。</p><h2 id="为什么同一个网关-不同工具填法还不一样" tabindex="-1">为什么同一个网关，不同工具填法还不一样 <a class="header-anchor" href="#为什么同一个网关-不同工具填法还不一样" aria-label="Permalink to &quot;为什么同一个网关，不同工具填法还不一样&quot;">​</a></h2><p>很多人第一次接入时最困惑的，就是明明都是同一个 小蓝中转站，为什么有的工具填根地址，有的工具要填 <code>/v1</code>。</p><p>原因不是文档前后矛盾，而是<strong>不同客户端本来就说着不同的协议</strong>：</p><ul><li><strong>Claude Code / Gemini CLI / Cherry Studio</strong> 这类工具，很多时候会自己继续补后面的协议路径，所以更适合填根地址</li><li><strong>Codex / OpenAI 兼容脚本 / 一部分 OpenAI 兼容工具</strong>，本身就要求你把 <code>/v1</code> 这层一起写进去</li></ul><p>也就是说，小蓝中转站 是同一个，但每个客户端和它对话的方式不完全一样。<br> 真正要记的不是“永远填根地址”或“永远带 <code>/v1</code>”，而是：<strong>以当前工具的接入方式为准</strong>。</p><h2 id="账号、余额、key、模型在这层里分别负责什么" tabindex="-1">账号、余额、Key、模型在这层里分别负责什么 <a class="header-anchor" href="#账号、余额、key、模型在这层里分别负责什么" aria-label="Permalink to &quot;账号、余额、Key、模型在这层里分别负责什么&quot;">​</a></h2><p>第一次接入时，很多报错其实不是“网关坏了”，而是这几层还没分清：</p><table tabindex="0"><thead><tr><th>项目</th><th>负责什么</th></tr></thead><tbody><tr><td>账号</td><td>让你进入控制台</td></tr><tr><td>余额</td><td>让请求有可用预算</td></tr><tr><td>Key</td><td>让客户端通过鉴权</td></tr><tr><td>模型</td><td>决定这次实际调用谁</td></tr></tbody></table><p>常见顺序是：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>先注册账号 -&gt; 充值小额余额 -&gt; 创建 Key -&gt; 复制模型名 -&gt; 配客户端</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>只要其中一层没准备好，表面上都可能看起来像“接口不通”。</p><h2 id="第一次怎么理解才不容易乱" tabindex="-1">第一次怎么理解才不容易乱 <a class="header-anchor" href="#第一次怎么理解才不容易乱" aria-label="Permalink to &quot;第一次怎么理解才不容易乱&quot;">​</a></h2><p>第一次接入时，不必先把“网关”想成一套复杂架构。<br> 更实用的理解方式是：</p><ol><li>先把它当成一个统一入口</li><li>用一把专属 Key 先让一个工具跑通</li><li>跑通以后，再把第二个、第三个工具也接进来</li></ol><p>这样做的好处是，你能先证明：</p><ul><li>账号和余额没问题</li><li>Key 能鉴权</li><li>模型名可用</li><li>当前这个客户端的地址填法是对的</li></ul><p>只要第一条链路跑通，后面再接第二个工具时，问题范围就会小很多。</p><h2 id="接下来该看哪里" tabindex="-1">接下来该看哪里 <a class="header-anchor" href="#接下来该看哪里" aria-label="Permalink to &quot;接下来该看哪里&quot;">​</a></h2><p>卡在“为什么要有这一层”时，连着看这两页最合适：</p><ol><li><a href="/intro/overview">为什么需要 小蓝中转站 网关？</a></li><li><a href="/guide/quick-start">快速接入</a></li></ol><p>前者帮助你建立概念，后者直接带你跑第一条可用链路。</p>',32)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
